var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>전 병력에 전파한다! 현 시간부로 지정된 포대로 이동해라!</color>","JPN":"<color=#ffd34c>全兵力に告ぐ！　現時刻より指定の砲台へ移動せよ！</color>","ENG":"<color=#ffd34c>Attention, all troops! Move out to your designated batteries immediately!</color>","TWN":"<color=#ffd34c>通知所有戰鬥人員！現在立即前往指定炮臺！</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"전대장에게 잡아 먹히기 싫으면 꾸물대지 말고 움직여!","JPN":"戦隊長に喰われたくなければ、もたもたしないで動け！","ENG":"Get moving if you don't want the Commander to devour you!","TWN":"如果不想被隊長吃掉，就給我動作快點！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"뭐야? 돌아오자마자 이건 또 무슨 난리야?","JPN":"何？　帰ってきたとたんに何の騒ぎなの？","ENG":"Huh? What's all the commotion about?","TWN":"什麼？剛回來又要做什麼？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"방주의 봉인이 약해졌다.","JPN":"箱舟の封印が弱まった。","ENG":"The Ark's seal has grown weak.","TWN":"方舟的封印變弱了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"클리파 차원으로부터 점점 더 강력한 에너지가 쏟아져 들어오고 있어.","JPN":"クリファ次元から強力なエネルギーが流れ込んできている。","ENG":"The energy flowing in from the Qlipha dimension is growing more and more powerful.","TWN":"從逆卡巴拉湧出了更強的能量。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"이 힘을 이용해서 싸우자고 한 건 네 의견이었을 텐데?","JPN":"この力を用いて戦おうと進言したのは貴様だろう？","ENG":"I thought it was your idea to use that power to fight?","TWN":"妳不是提議說，要利用這股力量戰鬥嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"맞아. 하지만 이렇게 성급하게 굴 필요는 없잖아.","JPN":"ええ。でもそんなに急ぐことはないんじゃない？","ENG":"True. But there's no need to rush like this.","TWN":"沒錯，但沒必要這麼急躁。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"충분한 힘을 얻으려면 시간이 필요해.","JPN":"十分な力を得るには時間が必要よ。","ENG":"We'll need more time to get enough power.","TWN":"要獲得充分的力量需要時間。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"굳이 싸워서 애들을 쓸데없이 희생시키지 않아도 된다고.","JPN":"無駄に戦って、子どもたちに余計な犠牲を強いることはないわ。","ENG":"We don't need to fight so quickly and sacrifice the troops for no reason.","TWN":"沒必要硬拼，讓孩子們白白犧牲。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"왜? 네가 잡아먹을 먹이가 줄어들어서 아쉽기라도 한가?","JPN":"貴様の獲物が減ってしまうのがそんなに残念か？","ENG":"Why not? Are you disappointed to lose prey you can feed on?","TWN":"怎麼？妳是怕妳的食物減少嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"무슨 소리야?","JPN":"何言ってるの？","ENG":"What are you talking about?","TWN":"妳在說什麼？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"먹이라니, 난 그저......","JPN":"獲物だなんて、私はただ……","ENG":"Prey? I was just—","TWN":"什麼食物，我只是……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"네가 뒤에서 내 병력을 야금야금 갉아먹는 걸 내가 모를 줄 알았나?","JPN":"裏で私の兵力を少しずつ喰い荒らしていただろう。\\n私が気付いていないとでも思ったか？","ENG":"Did you think I wouldn't notice you nibbling away at my troops?","TWN":"妳以為我不知道妳背著我，一點一點地在吞噬我的兵力嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그러고 보니 발레리가 안 보이는군. 어디 두고 왔는지 궁금해지는데.","JPN":"そういえばヴァレリーの姿が見えないな。\\nどこかに置き去りにしたとも思えないが。","ENG":"Speaking of which, I do not see Valeriy here. I'm starting to wonder where you left him.","TWN":"我怎麼沒看到瓦萊里，真好奇妳把他弄去哪了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"......쳇. 사레들게 하네.","JPN":"……チッ。消化に悪いったらないわね。","ENG":"Tsk. You almost made me choke.","TWN":"……切，妳差點害我噎到。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그래. 내가 흡수했어.","JPN":"そうよ。私が吸収したわ。","ENG":"Yes. I absorbed him.","TWN":"沒錯，是我把他吸收了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"내버려 두면 죽을 텐데 그냥 버리는 것보단 낫잖아?","JPN":"だって放っておくと死んじゃうのよ。そのまま捨てちゃうより良いでしょう？","ENG":"He was going to die anyway. Waste not, want not.","TWN":"反正我不吃他也會死，不如讓我吃掉還比較好吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};